/**
 * Tests for the interaction between take() and onCompletion() operators.
 * See https://github.com/Kotlin/kotlinx.coroutines/issues/XXXX
 */
class TakeOnCompletionTest : TestBase() {

    @Test
    fun testTakeWithOnCompletionAndFirst() = runTest {
        // This should not hang
        val result = withTimeoutOrNull(1000) {
            flowOf(1)
                .take(1)
                .onCompletion { if (it == null) awaitCancellation() }
                .first()
        }
        assertEquals(1, result)
    }

    @Test
    fun testTakeMultipleWithOnCompletionAndFirst() = runTest {
        // This should not hang even with take(100) on a flow with fewer elements
        val result = withTimeoutOrNull(1000) {
            flowOf(1, 2, 3)
                .take(100)
                .onCompletion { if (it == null) awaitCancellation() }
                .first()
        }
        assertEquals(1, result)
    }

    @Test
    fun testTakeWithOnCompletionAndFirstOrNull() = runTest {
        // This should not hang with firstOrNull
        val result = withTimeoutOrNull(1000) {
            flowOf(1)
                .take(1)
                .onCompletion { if (it == null) awaitCancellation() }
                .firstOrNull()
        }
        assertEquals(1, result)
    }

    @Test
    fun testTakeWithOnCompletionCollectingAll() = runTest {
        // When collecting all elements, onCompletion should see null (successful completion)
        // and awaitCancellation should be called, causing the flow to hang
        assertFailsWith<TimeoutCancellationException> {
            withTimeout(1000) {
                flowOf(1)
                    .take(1)
                    .onCompletion { if (it == null) awaitCancellation() }
                    .collect()
            }
        }
    }

    @Test
    fun testTakeWithOnCompletionAndSingle() = runTest {
        // This should not hang with single()
        val result = withTimeoutOrNull(1000) {
            flowOf(1)
                .take(1)
                .onCompletion { if (it == null) awaitCancellation() }
                .single()
        }
        assertEquals(1, result)
    }

    @Test
    fun testTakeWithOnCompletionAndFirstWithPredicate() = runTest {
        // This should not hang with first(predicate)
        val result = withTimeoutOrNull(1000) {
            flowOf(1, 2, 3)
                .take(5)
                .onCompletion { if (it == null) awaitCancellation() }
                .first { it > 0 }
        }
        assertEquals(1, result)
    }

    @Test
    fun testTakeExactCountWithOnCompletion() = runTest {
        // When take count exactly matches the flow size, and we use first(),
        // onCompletion should see an exception (not null) and should not hang
        val result = withTimeoutOrNull(1000) {
            flowOf(1, 2, 3)
                .take(3)
                .onCompletion { if (it == null) awaitCancellation() }
                .first()
        }
        assertEquals(1, result)
    }

    @Test
    fun testTakeWithOnCompletionThatEmits() = runTest {
        // Test that onCompletion can still emit when the flow is cancelled normally
        val results = mutableListOf<Int>()
        val exception = assertFailsWith<TimeoutCancellationException> {
            withTimeout(1000) {
                flowOf(1, 2, 3)
                    .take(2)
                    .onCompletion { cause ->
                        if (cause != null) {
                            // Flow was cancelled, can emit completion marker
                            emit(-1)
                        }
                    }
                    .onEach { results.add(it) }
                    .first()
            }
        }
        // first() should cancel after receiving the first element
        // onCompletion should see the cancellation and emit -1
        // But since first() already completed, the -1 won't be collected
        assertEquals(listOf(1), results)
    }
}
